   400→	async search({
   401→		indexName,
   402→		body,
   403→		searchPipeline,
   404→	}: {
   405→		indexName: string;
   406→		body: Record<string, unknown>;
   407→		searchPipeline?: string;
   408→	}): Promise<{
   409→		hits: { _id: string; _score: number; _source: Record<string, unknown> }[];
   410→		ext?: Record<string, unknown>;
   411→	}> {
   412→		try {
   413→			const searchParams: Record<string, unknown> = { index: indexName, body };
   414→
   415→			if (searchPipeline) {
   416→				searchParams['search_pipeline'] = searchPipeline;
   417→			}
   418→
   419→			const response = await this.client.search(searchParams);
   420→
   421→			const hits = (
   422→				response.body.hits.hits as {
   423→					_id: string;
   424→					_score: number;
   425→					_source: Record<string, unknown>;
   426→				}[]
   427→			).map((hit) => ({
   428→				_id: hit._id,
   429→				_score: hit._score,
   430→				_source: hit._source,
   431→			}));
   432→
   433→			const ext = response.body.ext as Record<string, unknown> | undefined;
   434→
   435→			return { hits, ext };
   436→		} catch (error: unknown) {
   437→			this.handleError({ context: `Search failed on index ${indexName}`, error });
   438→			throw error;
   439→		}
