   438→	private normalizeCondensedFeatures({
   439→		condensedFeatures,
   440→	}: {
   441→		condensedFeatures: unknown;
   442→	}): string[] | null {
   443→		if (condensedFeatures === null || condensedFeatures === undefined) {
   444→			return null;
   445→		}
   446→
   447→		if (typeof condensedFeatures === 'string') {
   448→			return [condensedFeatures];
   449→		}
   450→
   451→		if (Array.isArray(condensedFeatures)) {
   452→			return condensedFeatures.map(String);
   453→		}
   454→
   455→		if (typeof condensedFeatures === 'object') {
   456→			return Object.values(condensedFeatures).flatMap((value: unknown) =>
   457→				Array.isArray(value) ? value.map(String) : [String(value)],
   458→			);
   459→		}
   460→
   461→		return [JSON.stringify(condensedFeatures)];
   462→	}
