   464→	private buildCombinedTextForEmbedding({ style }: { style: IStylesMvBase }): string {
   465→		const normalizedCondensedFeatures = this.normalizeCondensedFeatures({
   466→			condensedFeatures: style.condensed_features,
   467→		});
   468→		const priceLvlMap: Record<string, string> = {
   469→			1: 'Budget',
   470→			2: 'Mid-range',
   471→			3: 'Premium',
   472→		};
   473→		const mappedPriceLevel: string | null =
   474→			style.price_level && priceLvlMap[String(style.price_level)]
   475→				? (priceLvlMap[String(style.price_level)] ?? null)
   476→				: (priceLvlMap['2'] ?? null);
   477→
   478→		const parts: string[] = [
   479→			...(style.name ? [this.cleanText({ text: style.name })] : []),
   480→			...(style.product_type ? [this.cleanText({ text: style.product_type })] : []),
   481→			...(mappedPriceLevel ? [`Price lvl: ${mappedPriceLevel}`] : []),
   482→			...(style.brand?.length
   483→				? [`Brand: ${this.cleanText({ text: style.brand[0] })}`]
   484→				: []),
   485→			...(normalizedCondensedFeatures?.length
   486→				? [this.cleanText({ text: normalizedCondensedFeatures.join(', ') })]
   487→				: []),
   488→			...(style.style_type ? [this.cleanText({ text: style.style_type })] : []),
   489→			...(style.primary_category_name
   490→				? [`Category: ${this.cleanText({ text: style.primary_category_name })}`]
   491→				: []),
   492→			...(style.manufacturer
   493→				? [`From: ${this.cleanText({ text: style.manufacturer })}`]
   494→				: []),
   495→			...(style.sub_category_names?.length
   496→				? [
   497→						`Subcategories: ${this.cleanText({ text: style.sub_category_names.join(', ') })}`,
   498→					]
   499→				: []),
   500→			...(style.decoration_method
   501→				? [`Decoration: ${this.cleanText({ text: style.decoration_method })}`]
   502→				: []),
   503→			...(style.features
   504→				? [`Features: ${this.cleanText({ text: style.features })}`]
   505→				: []),
   506→		];
   507→
   508→		const combinedText = parts.filter(Boolean).join('. ');
   509→
   510→		this.logger.debug(
   511→			`Combined text length for style_id ${style.style_id}: ${combinedText.length} characters`,
   512→		);
   513→
   514→		return combinedText;
   515→	}
   516→
   517→	private cleanText({ text }: { text: string | null | undefined }): string {
   518→		if (!text) return '';
   519→		return text
   520→			.replace(/\r\n|\r|\n/g, ' ')
   521→			.replace(/[*#]+\s?/g, '')
   522→			.replace(/<[^>]*>/g, '')
   523→			.replace(/\s{2,}/g, ' ')
   524→			.trim();
   525→	}
