   531→	}): IOpensearchProduct {
   532→		return {
   533→			_id: style._id,
   534→			style_id: style.style_id,
   535→			product_id: style.product_id,
   536→			name: style.name ?? '',
   537→			features: style.features,
   538→			general_comments: style.general_comments,
   539→			decoration_method: style.decoration_method,
   540→			manufacturer: style.manufacturer,
   541→			primary_category_id: style.primary_category_id,
   542→			primary_category_name: style.primary_category_name,
   543→			product_type: style.product_type,
   544→			style_type: style.style_type,
   545→			broad_category_names: style.broad_category_names,
   546→			sub_category_names: style.sub_category_names,
   547→			minimum_quantity: style.minimum_quantity,
   548→			min_qty: style.min_qty,
   549→			default_quote_qty: style.default_quote_qty,
   550→			sizes: style.sizes,
   551→			turn_time: style.turn_time,
   552→			rush_turn_time: style.rush_turn_time,
   553→			no_minimum: style.no_minimum ? 1 : 0,
   554→			price_level: style.price_level,
