    90→		message: string;
    91→		conversationId?: string;
    92→		clarifications?: ClarificationAnswerDto[];
    93→	}): Promise<ConversationalSearchResponseDto> {
    94→		if (conversationId) {
    95→			return this.handleContinuation({ message, conversationId });
    96→		}
    97→
    98→		if (!clarifications?.length) {
    99→			return this.handleNewConversation({ message });
   100→		}
   101→
   102→		return this.handleWithClarifications({ message, clarifications });
   103→	}
   104→
   105→	private async handleContinuation({
   106→		message,
   107→		conversationId,
   108→	}: {
   109→		message: string;
   110→		conversationId: string;
   111→	}): Promise<ConversationalSearchResponseDto> {
   112→		const sanitized = this.opensearchConversationalService.sanitizeQuery({ text: message });
   113→		const normalized = this.opensearchConversationalService.normalizeQuery({
   114→			text: sanitized,
   115→		});
   116→
   117→		const { products, answer } = await this.opensearchConversationalService.searchProducts({
   118→			queryText: normalized,
   119→			memoryId: conversationId,
   120→			llmQuestion: message,
   121→		});
   122→
   123→		return {
   124→			needsClarification: false,
   125→			conversationId,
   126→			query: normalized,
   127→			summary: answer ?? `Found ${products.length} products matching your request.`,
   128→			total: products.length,
   129→			products,
   130→		};
   131→	}
   132→
   133→	private async handleNewConversation({
   134→		message,
   135→	}: {
   136→		message: string;
   137→	}): Promise<ConversationalSearchResponseDto> {
   138→		const sanitized = this.opensearchConversationalService.sanitizeQuery({
   139→			text: message,
   140→		});
   141→
   142→		const triggeredRules = this.CLARIFICATION_RULES.filter((rule) =>
   143→			rule.check(sanitized),
   144→		);
   145→
   146→		const hasStrongSignal = this.hasStrongProductSignal({ text: sanitized });
   147→
   148→		if (triggeredRules.length >= MIN_CLARIFICATIONS_NEEDED && !hasStrongSignal) {
   149→			const questions: ClarificationQuestionDto[] = triggeredRules.map((rule) => ({
   150→				id: rule.id,
   151→				question: rule.question,
   152→				options: rule.options,
   153→			}));
   154→
   155→			return { needsClarification: true, questions };
   156→		}
   157→
   158→		return this.handleWithClarifications({ message, clarifications: [] });
   159→	}
   160→
   161→	private async handleWithClarifications({
   162→		message,
   163→		clarifications,
   164→	}: {
   165→		message: string;
   166→		clarifications: ClarificationAnswerDto[];
   167→	}): Promise<ConversationalSearchResponseDto> {
   168→		const clarificationParts = clarifications.map((c) => {
   169→			const rule = this.CLARIFICATION_RULES.find((r) => r.id === c.questionId);
   170→			const option = rule?.options.find((o) => o.value === c.answer);
   171→			return option?.label ?? c.answer;
   172→		});
   173→
   174→		const enrichedQuery = [message, ...clarificationParts].filter(Boolean).join(' ');
   175→
   176→		const sanitized = this.opensearchConversationalService.sanitizeQuery({
   177→			text: enrichedQuery,
   178→		});
   179→		const normalized = this.opensearchConversationalService.normalizeQuery({
   180→			text: sanitized,
   181→		});
   182→
   183→		const conversationId = await this.opensearchService.createConversation({
   184→			name: message.substring(0, 50),
   185→		});
   186→
   187→		const { products, answer } = await this.opensearchConversationalService.searchProducts({
   188→			queryText: normalized,
   189→			memoryId: conversationId,
   190→			llmQuestion: enrichedQuery,
   191→		});
   192→
   193→		return {
   194→			needsClarification: false,
   195→			conversationId,
   196→			query: normalized,
   197→			summary: answer ?? `Found ${products.length} products matching your request.`,
   198→			total: products.length,
   199→			products,
   200→		};
   201→	}
   202→
   203→	private hasStrongProductSignal({ text }: { text: string }): boolean {
   204→		const strongSignals =
   205→			/\b(polo|hoodie|jacket|hat|cap|bag|mug|pen|notebook|shirt|pants|shorts|socks|shoes|sneakers|sweatshirt|fleece|vest|beanie|gloves|scarf|backpack|tote|water bottle|tumbler|keychain|lanyard|umbrella|polo shirt|t-shirt|tank top|zip-up|half-zip|long-sleeve|short-sleeve|crewneck|v-neck)\b/i;
   206→		return strongSignals.test(text) && text.split(' ').length >= 4;
   207→	}
